const dryRun = true;
const includeTestAlert = false;

const body = {};
if (dryRun) body.dry_run = true;
if (includeTestAlert) body.include_test_alert = true;

return [{
  json: {
    request_body: body,
    workflow_mode: dryRun ? "dry_run" : "apply",
    notes: "Manual dry-run test mode. No Telegram alert should be sent while dryRun=true.",
  },
}];

const response = $json || {};

if (response.success !== true || response.status !== "ok") {
  return [];
}

// Safety rule: never send from dry-run output.
if (response.mode !== "apply") {
  return [];
}

const alerts = Array.isArray(response.sendable_alerts) ? response.sendable_alerts : [];
const safeAlerts = alerts.filter((alert) => {
  const details = alert && typeof alert.details === "object" && alert.details !== null ? alert.details : {};
  if (alert.alert_type === "BACKEND_AUDIT_TEST") return false;
  if (details.test === true) return false;
  if (details.safe_to_ignore === true) return false;
  return true;
});

return safeAlerts.map((alert) => ({
  json: {
    ...alert,
    evaluator_mode: response.mode,
    evaluator_status: response.status,
  },
}));

const CHARL_TELEGRAM_CHAT_ID = "5721652188";

function clean(value) {
  return String(value ?? "").trim();
}

function formatDateTime(iso) {
  if (!iso) return "unknown";
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return iso;
  return new Intl.DateTimeFormat("en-ZA", {
    timeZone: "Africa/Johannesburg",
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  }).format(d);
}

return $input.all().map((item) => {
  const alert = item.json || {};
  const severity = clean(alert.severity || "warning").toUpperCase();
  const sourceName = clean(alert.source_name || alert.source_id || "Weather telemetry");
  const alertType = clean(alert.alert_type || "WEATHER_ALERT");
  const message = clean(alert.message || "Weather alert triggered.");
  const text = [
    `Weather alert: ${severity}`,
    "",
    message,
    "",
    `Source: ${sourceName}`,
    `Time: ${formatDateTime(alert.event_at)}`,
    `Alert: ${alertType}`,
  ].join("\n");

  return {
    json: {
      chatId: CHARL_TELEGRAM_CHAT_ID,
      telegram_text: text,
      alert_id: alert.alert_id,
      alert_key: alert.alert_key,
      alert_type: alertType,
      severity: alert.severity,
      _alert: alert,
    },
  };
});
